from pydantic import BaseModel

# Import your custom agents and tools
from src.agents.research_module import ResearchModule
from src.agents.coding_module import CodingModule
from src.agents.support_module import SupportModule

class MultiAgentServer:
    def __init__(self):
        # Initialize FastAPI app
        self.app = FastAPI(
            title="Multi-Agent API",
            description="Advanced AI Agent Workflow API",
            version="1.0.0"
        )

        # Initialize agents
        self.research_agent = ResearchModule()
        self.coding_agent = CodingModule()
        self.support_agent = SupportModule()

        # Setup checkpointer
        self.checkpointer = MemorySaver()

        # Setup routes
        self._setup_routes()

    def _setup_routes(self):
        """
        Configure API routes for different agents
        """
        @self.app.post("/research")
        async def research_endpoint(request: Dict[str, Any]):
            """
            Research agent endpoint with advanced error handling
            """
            try:
                query = request.get('query')
                if not query:
                    raise HTTPException(status_code=400, detail="Query is required")

                # Run research agent workflow
                result = self.research_agent.agent.invoke(
                    {"input": query},
                    {"configurable": {"thread_id": "research_thread"}}
                )

                return {
                    "status": "success",
                    "result": result.get('final_answer', 'No results found'),
                    "metadata": {
                        "query_length": len(query),
                        "agent": "research"
                    }
                }
            except Exception as e:
                return {
                    "status": "error",
                    "message": str(e),
                    "code": 500
                }

        @self.app.post("/code-generation")
        async def code_generation_endpoint(request: Dict[str, Any]):
            """
            Code generation agent endpoint
            """
            try:
                task = request.get('task')
                language = request.get('language', 'python')

                if not task:
                    raise HTTPException(status_code=400, detail="Task description is required")

                result = self.coding_agent.agent.invoke(
                    {
                        "input": task,
                        "language": language
                    },
                    {"configurable": {"thread_id": "code_generation_thread"}}
                )

                return {
                    "status": "success",
                    "code": result.get('generated_code', ''),
                    "metadata": {
                        "language": language,
                        "task_complexity": len(task)
                    }
                }
            except Exception as e:
                return {
                    "status": "error", 
                    "message": str(e)
                }

        @self.app.post("/support")
        async def support_endpoint(request: Dict[str, Any]):
            """
            Support agent endpoint
            """
            try:
                query = request.get('query')
                context = request.get('context', {})

                if not query:
                    raise HTTPException(status_code=400, detail="Query is required")

                result = self.support_agent.agent.invoke(
